void Ultrasonic_Trigger(void)
{
    GPIO_Write_Output_Pin(GPIOA, 0, DISABLE);
	delay_us(2);
    GPIO_Write_Output_Pin(GPIOA, 0, ENABLE);
    delay_us(10);
    GPIO_Write_Output_Pin(GPIOA, 0, DISABLE);
}

