int main(void)
{
	// Enable CP10 and CP11 full access
		SCB_CPACR |= (0xF << 20);
	// Disable lazy stacking
	    FPU_FPCCR &= ~((1 << 31) | (1 << 30)); // ASPEN=bit31, LSPEN=bit30


	    GPIO_peripherial_Clk_Cntrl(GPIOA,SET);
		GPIO_peripherial_Clk_Cntrl(GPIOC,SET);

	    TIM1_PCLK_EN();
	    TIM2_PCLK_EN();
		SPI_PCLK_EN(SPI1,SET);
		SPI_PeripheralControl(SPI1,ENABLE);
	    GPIO_Config();
		Button_Gpio_Config();
	    Tim1_GPIO_Config();
		SPI1_GPIO_Config();

		SPI_Config();
		SPI_PeripheralControl(SPI1,ENABLE);


	    TIM_Handle_t htim1;
	    TIM2345_Handle_t htim2;


	    htim1.pTIMx = TIM1;

	    htim1.TIM_Config.Prescaler = 3;
	    htim1.TIM_Config.Period = 0xFFFF;   // better for capture test
	    htim1.TIM_Config.ICPolarity = TIM_IC_RISING_EDGE;
	    htim1.TIM_Config.ICSelection = TIM_ICSELECTION_DIRECTTI;

	    htim2.pTIMx = TIM2;
	    htim2.TIM2345_Config.Prescaler = 3;
	    htim2.TIM2345_Config.Period = 0xFFFFFFFF;

	    TIM_Init(&htim1);
	    TIM_IC_Init(&htim1);
	    TIM_Start(TIM1);
	    TIM2345_Init(&htim2);
	    TIM2345_Start(TIM2);

	    TIM2->CR1 |= (0x01<<0);

	    TIM1->DIER |= (1 << 1);


		GPIO_IRQInterruptConfig(IRQ_NO_EXTI15_10, ENABLE);

		GPIO_IRQPriorityConfig(IRQ_NO_EXTI15_10, 1);

	    Timer_IRQInterruptConfig(TIM1_CC_IRQn, ENABLE);

	    Timer_IRQPriorityConfig(TIM1_CC_IRQn, 0);


	    w25q_reset();

	    flash_id = w25q_readID();
//
//	    while(w25q_read_status() & 0x01);
//
//	    w25q_write(0x000000, (uint8_t*)&ft, 4);
//
//	    while(w25q_read_status() & 0x01);
//
//	    w25q_read(0x000000, (uint8_t*)&r_ft, 4);



        // Loop forever
	    while(1)
	    {
	        system_time++;

	        measurement_done = 0;

	        Ultrasonic_Trigger();

	        uint32_t timeout = 500000;

	        while((measurement_done == 0) && timeout--);

	        float distance = distance_cm;

//	        printf("Distance : %.2f cm\r\n",distance);

	        /****************************************
	         * OBJECT ENTER DETECTION
	         ****************************************/
	        if((distance < OBJECT_THRESHOLD) &&
	           (object_present == 0))
	        {
	            object_present = 1;

	            printf("OBJECT ENTERED\r\n");

	            Store_Log(OBJECT_ENTER,
	                      distance);
	        }

	        /****************************************
	         * OBJECT EXIT DETECTION
	         ****************************************/
	        else if((distance > OBJECT_THRESHOLD) &&
	                (object_present == 1))
	        {
	            object_present = 0;

	            printf("OBJECT EXITED\r\n");

	            Store_Log(OBJECT_EXIT,
	                      distance);
	        }

	        /****************************************
	         * BUTTON PRESSED
	         ****************************************/
	        if(Exti_Flag)
	        {
	            delay_ms(200);

	            Exti_Flag = 0;

	            Read_All_Logs();
	        }

	        delay_ms(100);
	    }


}


