void TIM1_CC_IRQHandler(void)
{
    if(TIM1->SR & (1 << 1))
    {
        uint32_t capture = TIM1->CCR1;

        TIM1->SR &= ~(1 << 1);

        if(capture_state == 0)
        {
            rising_time = capture;

            TIM1->CCER |= (1 << 1);

            capture_state = 1;
        }
        else
        {
            falling_time = capture;
            uint32_t pulse;

            if(falling_time >= rising_time)
            {
                pulse = falling_time - rising_time;
            }
            else
            {
                pulse = (0xFFFF - rising_time + 1) + falling_time;
            }

//            distance_cm = pulse * 100 / 5800;

            distance_cm = pulse /58.0;

            capture_state = 0;

            TIM1->CCER &= ~(1 << 1);

            measurement_done = 1;
        }
    }
}

